"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["554020"],{626704(e){e.exports=JSON.parse('{"tag":{"label":"lookup configuration","permalink":"/sdk/4.8.1/tags/lookup-configuration","allTagsPath":"/sdk/4.8.1/tags","count":1,"items":[{"id":"guides/data-lookup-guide","title":"Data Lookup","description":"Guide for creating ServiceNow Data Lookup definitions (dl_definition) using the Fluent API. A Data Lookup connects a source table to a configurable matcher table and defines which source fields are used to find a matching row and which values are copied back to the source record. In simple terms form field change, record insert, and record update. If you find yourself reaching for a Business Rule (for insert/update) plus a Client Script (for onChange) to implement the same deterministic field-population logic, use Data Lookup instead.","permalink":"/sdk/4.8.1/guides/data-lookup-guide"}],"unlisted":false}}')}}]);